variant Choice {
  A;
  B;
}

fn choose(value: Choice) -> Text {
  match value {
    Choice::A => {
      "a"
    },
  }
}

fn choose(flag: Bool) -> Text {
  if flag {
    "a"
  } else {
    1
  }
}

variant Choice {
  A;
  B;
}

fn choose(value: Choice) -> Text {
  match value {
    Choice::A => {
      "a"
    },
    Choice::B => {
      1
    },
  }
}
